routeCards=function(chapter){return Object.entries(D.leads).filter(([,l])=>l.chapter==chapter).map(([k,l])=>{let state=S.leads[k]||'unknown',body=`${l.text}<br><b>Where:</b> ${n(l.node).name} - <b>Check:</b> ${l.stat.toUpperCase()} ${l.dc}<br>${leadCheckLine(l)}<br><b>Reward:</b> ${l.item?item(l.item).name:'none'}<br><b>State:</b> ${tag(state,state=='viable'?'green':state=='failed_forward'?'red':state=='rumored'?'gold':'')}${l.transformsTo?'<br><b>Failed-forward:</b> '+l.transformsTo.map(x=>D.leads[x]?.name||x).join(', '):''}`;return card(l.name,body,routeCardAction(k,l,state))}).join('')};
title=function(){app.innerHTML=header()+`<div class="panel"><h2>v0.8.0-dev1 - Greyhook Complete Flow Pass</h2><p>The first full Greyhook flow pass: route families, alert ladder, interior scenes, prisoner fate, companion reactions, aftermath, and next chapter hook.</p>${btn('New Game','reset()','pri')}${btn(hasStoredSave()?'Continue':'Start from party draft','continueGame()','good')}${btn('Jump to Greyhook test state','devGreyhook()')}</div>`};
map=function(){let exits=n(S.node).exits;let line=(a,b)=>{let A=pos[a],B=pos[b],x=A[0]+42,y=A[1]+23,dx=B[0]-A[0],dy=B[1]-A[1],l=Math.hypot(dx,dy),ang=Math.atan2(dy,dx)*180/Math.PI;return `<div class="road" style="left:${x}px;top:${y}px;width:${l}px;transform:rotate(${ang}deg)"></div>`};let nodes=Object.keys(D.nodes).map(id=>`<div class="node ${id==S.node?'cur':exits.includes(id)?'avail':''} ${hasLeadAt(id)?'leadnode':''}" style="left:${pos[id][0]}px;top:${pos[id][1]}px" onclick="${id==S.node?'go(\'node\')':exits.includes(id)?`travel(\'${id}\')`:''}">${n(id).name}</div>`).join('');app.innerHTML=header()+`<div class="panel">${guidePanel()}<h2>Map</h2><div class="mapViewport"><div class="map">${roads.map(r=>line(r[0],r[1])).join('')}${nodes}</div></div>${btn('Current node','go("node")','pri')}${btn('Case Board','go("board")','good')}</div><div class="panel"><h2>Road Log</h2><div class="log">${S.log.map(x=>'- '+x+'<br>').join('')}</div></div>`};
company=function(){app.innerHTML=header()+`<div class="panel">${guidePanel()}<h2>Company</h2>${S.party.map(id=>{let c=comp(id);return card(`${c.name} - ${c.role}`,`${c.text}<br><b>${c.ability}:</b> ${c.effect}<br>${(c.tags||[]).map(x=>tag(x)).join('')}`)}).join('')}<h3>Morale</h3>${tag(S.morale||0,S.morale<0?'red':'green')}<h3>Companion Reactions</h3>${reactionCards()||'<p>No major reaction yet.</p>'}<h3>Crimes</h3>${S.crimes.map(c=>tag(c,'red')).join('')||'<p>No recorded crimes.</p>'}</div>`};
pack=function(){app.innerHTML=header()+`<div class="panel">${guidePanel()}<h2>Pack & Papers</h2>${S.items.map(id=>{let i=item(id);return card(`${i.name} - ${i.type}`,`${i.text}<br>${(i.tags||[]).map(x=>tag(x)).join('')}`)}).join('')||'<p>No special items yet.</p>'}</div>`};
map=function(){let exits=n(S.node).exits,scale=1.38,pad=24,pt=id=>[Math.round(pos[id][0]*scale+pad),Math.round(pos[id][1]*scale+pad)];let line=(a,b)=>{let A=pt(a),B=pt(b),x=A[0]+43,y=A[1]+23,dx=B[0]-A[0],dy=B[1]-A[1],l=Math.hypot(dx,dy),ang=Math.atan2(dy,dx)*180/Math.PI;return `<div class="road" style="left:${x}px;top:${y}px;width:${l}px;transform:rotate(${ang}deg)"></div>`};let nodes=Object.keys(D.nodes).map(id=>{let P=pt(id);return `<div class="node ${id==S.node?'cur':exits.includes(id)?'avail':''} ${hasLeadAt(id)?'leadnode':''}" style="left:${P[0]}px;top:${P[1]}px" onclick="${id==S.node?'go(\'node\')':exits.includes(id)?`travel(\'${id}\')`:''}">${n(id).name}</div>`}).join('');app.innerHTML=header()+`<div class="panel">${guidePanel()}<h2>Map</h2><div class="mapViewport"><div class="map">${roads.map(r=>line(r[0],r[1])).join('')}${nodes}</div></div>${btn('Current node','go("node")','pri')}${btn('Case Board','go("board")','good')}</div><div class="panel"><h2>Road Log</h2><div class="log">${S.log.map(x=>'- '+x+'<br>').join('')}</div></div>`};
function centerMapOnCurrent(){let vp=app.querySelector('.mapViewport'),cur=app.querySelector('.node.cur');if(!vp||!cur)return;vp.scrollLeft=Math.max(0,cur.offsetLeft-vp.clientWidth/2+cur.clientWidth/2);vp.scrollTop=Math.max(0,cur.offsetTop-vp.clientHeight/2+cur.clientHeight/2)}
const renderPlayableMap=map;
map=function(){renderPlayableMap();setTimeout(centerMapOnCurrent,0)};
const mapLayout={gate:[250,28],market:[360,125],inn:[486,182],chapel:[250,172],ditch:[70,150],road:[170,270],tower:[318,330],mill:[70,365],ford:[485,365],shrine:[230,338],grey_road:[250,455],muster_field:[86,455],quartermaster_tent:[86,292],greyhook_gate:[500,455],greyhook_outer_yard:[370,350],fortress_infirmary:[590,336],synod_archive:[590,210],lower_cells:[392,236],sealed_prisoner_cell:[392,82]};
map=function(){let exits=n(S.node).exits,pt=id=>mapLayout[id]||pos[id];let line=(a,b)=>{let A=pt(a),B=pt(b),x=A[0]+43,y=A[1]+23,dx=B[0]-A[0],dy=B[1]-A[1],l=Math.hypot(dx,dy),ang=Math.atan2(dy,dx)*180/Math.PI;return `<div class="road" style="left:${x}px;top:${y}px;width:${l}px;transform:rotate(${ang}deg)"></div>`};let nodes=Object.keys(D.nodes).map(id=>{let P=pt(id);return `<div class="node ${id==S.node?'cur':exits.includes(id)?'avail':''} ${hasLeadAt(id)?'leadnode':''}" style="left:${P[0]}px;top:${P[1]}px" onclick="${id==S.node?'go(\'node\')':exits.includes(id)?`travel(\'${id}\')`:''}">${n(id).name}</div>`}).join('');app.innerHTML=header()+`<div class="panel">${guidePanel()}<h2>Map</h2><div class="mapViewport"><div class="map">${roads.map(r=>line(r[0],r[1])).join('')}${nodes}</div></div>${btn('Current node','go("node")','pri')}${btn('Case Board','go("board")','good')}</div><div class="panel"><h2>Road Log</h2><div class="log">${S.log.map(x=>'- '+x+'<br>').join('')}</div></div>`;setTimeout(centerMapOnCurrent,0)};
function forage(){S.res.food+=2;S.res.day++;S.res.heat=Math.min(6,S.res.heat+1);log('Foraged for food. Heat rises as the road notices you.');render()} window.forage=forage;
rest=function(){let ate=S.res.food>0;S.res.food=Math.max(0,S.res.food-1);S.res.day++;S.res.heat=Math.max(0,S.res.heat-1);S.fatigue=Math.max(0,(S.fatigue||0)-2);if(S.perks.includes('camp_surgeon'))S.res.medicine=Math.max(0,(S.res.medicine||0)+1);if(ate&&S.morale<2)S.morale++;log(ate?'Rested, ate, and cooled the trail. Fatigue: '+S.fatigue+'/6.':'Rested hungry; heat cools, morale does not.');render()}; window.rest=rest;
function encodeSave(data){let bytes=new TextEncoder().encode(JSON.stringify(data));let text='';bytes.forEach(b=>text+=String.fromCharCode(b));return btoa(text)}
function decodeSave(code){let text=atob(code.trim());let bytes=Uint8Array.from(text,c=>c.charCodeAt(0));return JSON.parse(new TextDecoder().decode(bytes))}
function exportSave(){let payload=encodeSave(S),done=()=>{log('Save code exported.');render()};if(navigator.clipboard&&window.isSecureContext)navigator.clipboard.writeText(payload).then(done).catch(()=>{prompt('Copy save code',payload);done()});else{prompt('Copy save code',payload);done()}} window.exportSave=exportSave;
function importSave(){let payload=prompt('Paste save code');if(!payload||!payload.trim())return;try{let data=decodeSave(payload.trim());if(!data||typeof data!=='object')throw new Error('Invalid save data');let restored=hydrate(data);S=restored;log('Save code imported.');render()}catch(e){alert('Save import failed. Current save is unchanged.');log('Save import failed.');render()}} window.importSave=importSave;
function confirmReset(){if(confirm('Reset this run and return to party selection?'))reset()} window.confirmReset=confirmReset;

function debugStateText(){return [
  `Gravesmoke Road v${D.version}`,
  `Character: ${S.name||'?'}  Origin: ${S.origin||'none'}  Lv ${S.level}  XP ${S.xp||0}`,
  `Perks: ${S.perks.join(', ')||'none'}  Perk pts: ${S.perkPoints}`,
  `Screen: ${S.screen}  Node: ${S.node}  Settlement: ${S.settlement||'none'}`,
  `Party: ${S.party.join(', ')||'none'}  Morale: ${S.morale}`,
  `Food: ${S.res.food}  Fatigue: ${S.fatigue||0}/6  Heat: ${S.res.heat}/6  Day: ${S.res.day}  Coin: ${S.res.coin}`,
  `Greyhook inside: ${S.greyhookInside?'yes':'no'}  Route: ${S.greyhookRoute||'none'}  Alert: ${S.greyhookAlert}/5`,
  `Prisoner contact: ${S.prisonerContact?'yes':'no'}  Choice: ${S.prisonerChoice||'none'}  Outcome: ${S.prisonerOutcome||'none'}`,
  `Aftermath: ${S.aftermath||'none'}  Flags: ${Object.keys(S.flags).length}  Items: ${S.items.length}  Solutions: ${S.solutions.length}`,
  `Crimes: ${S.crimes.length}  Enemy type: ${S.enemyType}  Pressure: ${S.enemyPressure}`,
  `Wounds: ${S.wounds||0}  Last routes: ${S.routeHistory.slice(-5).join(', ')||'none'}`
].join('\n')}
function copyDebugState(){let t=debugStateText();let done=()=>log('Debug state copied.');let fail=()=>{let el=document.querySelector('.debugDetails');if(el)el.open=true;log('Copy unavailable. Raw state visible below.')};if(navigator.clipboard&&window.isSecureContext)navigator.clipboard.writeText(t).then(done).catch(fail);else fail();render()} window.copyDebugState=copyDebugState;
function debugStatePanel(){let rows=[
  ['Version',D.version,'Save',String(S.saveVersion||'?')],
  ['Name',S.name||'?','Origin',S.origin||'none'],
  ['Level',String(S.level),'XP',`${S.xp||0}`],
  ['Perks',S.perks.join(', ')||'none','Points',String(S.perkPoints)],
  ['Screen',S.screen,'node',n(S.node).name],
  ['Party',S.party.join(', ')||'none','Morale',String(S.morale)],
  ['Food',String(S.res.food),'Fatigue',`${S.fatigue||0}/6`],
  ['Heat',`${S.res.heat}/6`,'Day',String(S.res.day)],
  ['Coin',String(S.res.coin),'Med',String(S.res.medicine)],
  ['Greyhook inside',S.greyhookInside?'yes':'no','Route',S.greyhookRoute||'none'],
  ['Alert',`${S.greyhookAlert}/5 — ${greyhookAlertBand()}`,'Lockdown',isGreyhookLockdown()?'yes':'no'],
  ['Prisoner contact',S.prisonerContact?'yes':'no','Choice',S.prisonerChoice||'none'],
  ['Outcome',S.prisonerOutcome||'none','Aftermath',S.aftermath||'none'],
  ['Flags',String(Object.keys(S.flags).length),'Items',String(S.items.length)],
  ['Solutions',String(S.solutions.length),'Clues',String(S.clues.length)],
  ['Crimes',String(S.crimes.length),'Reactions',String(S.reactions.length)],
  ['Wounds',String(S.wounds||0),'Enemy',S.enemyType],
  ['Last routes',S.routeHistory.slice(-5).join(', ')||'none','']
];let table=rows.map(r=>`<tr>${r.map(c=>c?`<td>${escapeHtml(String(c))}</td>`:'<td></td>').join('')}</tr>`).join('');return `<div class="card debugPanel"><div class="ct">Debug State</div><table class="debugTable">${table}</table><details class="debugDetails"><summary>Raw State</summary><pre class="errorStack">${escapeHtml(JSON.stringify(S,null,2))}</pre></details>${btn('Copy Debug State','copyDebugState()','good')}${S.greyhookInside||!S.greyhook?'':btn('Jump to Greyhook test state','devGreyhook()')}${btn('Reset Save','confirmReset()','bad')}</div>`}

function actionGroup(title,html,cls=''){if(!html)return '';let key=cls.includes('danger')?'danger':cls.includes('travel')?'travel':cls.includes('scene')?'investigate':'resolve';return `<section class="actionGroup ${cls}"><div class="groupTitle">${assetImg(iconEntry(key),'groupIcon','')}<span>${title}</span></div><div class="actionGrid">${html}</div></section>`}
function resourcePill(label,value,cls='',icon='action'){return `<span class="resourcePill ${cls}">${assetImg(iconEntry(icon),'pillIcon','')}<span>${label}</span><b>${value}</b></span>`}
resourceRail=function(){let parts=[resourcePill('coin',S.res.coin,'gold','paper'),resourcePill('food',S.res.food,S.res.food<=1?'red':'','camp'),resourcePill('fatigue',`${S.fatigue||0}/6`,S.fatigue>=5?'red':S.fatigue>=3?'purple':'','travel'),resourcePill('heat',S.res.heat,S.res.heat>=4?'red':'','warning')];if(S.greyhook)parts.push(resourcePill('Greyhook',`${S.greyhookAlert}/5`,S.greyhookAlert>=4?'red':'purple','danger'));if(S.morale)parts.push(resourcePill('morale',S.morale,S.morale<0?'red':'green','company'));return `<div class="resourceRail">${parts.join('')}</div>`};
header=function(){return `<div class="head"><div><h1>Gravesmoke Road</h1><div class="mut">v${D.version} - Day ${S.res.day} - ${n(S.node).name}</div></div>${resourceRail()}</div>`};
guidePanel=function(){let a=guideAction();return `<div class="guidePanel"><div><div class="guideKicker">Current objective</div><div class="guideText">${recommendedNext()}</div></div>${btn(a.label,a.action,`mini ${a.cls||''}`)}</div>`};

function nodeActionGroups(){let g={primary:'',scene:'',danger:''};let ls=Object.entries(D.leads).filter(([k,l])=>l.node==S.node&&S.leads[k]=='rumored');if(ls.length)g.scene+=ls.map(([k,l])=>btn('Investigate: '+l.name+' ('+checkScore(l)+'/'+Math.max(0,l.dc-1)+')',`investigate('${k}')`,'good')).join('');if(S.node=='tower'&&S.contract&&!S.ledger)g.primary+=btn('Take the ledger by force or parley','ledgerWin()','pri');if(S.node=='greyhook_gate'){g.primary+=greyhookApproaches();g.scene+=sceneButtonsForNode('greyhook_gate')}if(S.node=='greyhook_outer_yard'){g.scene+=sceneButtonsForNode('greyhook_outer_yard');g.primary+=btn('Ask companion for Greyhook angle','companionAngle()','good');g.danger+=btn('Starting enemy interference','enemyInterferenceScene()','bad')}if(['quartermaster_tent','fortress_infirmary','lower_cells','synod_archive'].includes(S.node))g.scene+=sceneButtonsForNode(S.node);if(S.node=='sealed_prisoner_cell')g.primary+=sceneButtonsForNode('sealed_prisoner_cell')+prisonerButtons();if(isGreyhookLockdown())g.danger+=btn('Forced escape / capture pressure','escapeOrCapture()','bad');if(!g.primary&&!g.scene&&!g.danger)g.scene+=btn('Gather rumor','rumor()');return g}
function renderActionGroups(g){return actionGroup('Primary',g.primary,'primary')+actionGroup('Scene',g.scene,'scene')+actionGroup('Danger',g.danger,'danger')}
nodeActions=function(){return renderActionGroups(nodeActionGroups())};
nodeScreen=function(){let exits=n(S.node).exits.map(id=>btn('Travel to '+n(id).name,`travel('${id}')`,canUseExit(id)?'':'bad')).join('');let settleId=withinSettlement(),settleBtn=settleId?btn('Enter '+settle(settleId).name,`go('settlement')`,'pri'):'';let fat=tag(`Fatigue ${S.fatigue||0}/6`,S.fatigue>=5?'red':S.fatigue>=3?'purple':'');let danger=tmeta(S.node).danger>=4?tag('Hostile','red'):tmeta(S.node).danger>=3?tag('Dangerous','purple'):'';app.innerHTML=header()+`<div class="panel playPanel">${guidePanel()}${scenePanel(S.node)}<div class="locationBlock"><div class="guideKicker">Current location</div><h2>${n(S.node).name}</h2><p>${nodeText()}</p>${settleBtn}<div>${fat} ${danger}</div></div>${nodeActions()}${actionGroup('Travel',exits,'travel')}</div>`};

party=function(){let choices=S.pool.map(id=>{let c=comp(id);return `<div class="choice partyChoice ${S.party.includes(id)?'sel':''}" onclick="pickComp('${id}')">${portraitImg(id,'choicePortrait')}<div><div class="ct">${c.name} - ${c.role}</div><div class="cx">${c.text}<br><b>${c.ability}:</b> ${c.effect}<br>${(c.tags||[]).map(x=>tag(x)).join('')}</div></div></div>`}).join('');app.innerHTML=header()+`<div class="panel"><h2>Choose three companions</h2><p class="mut">Companions open Greyhook routes and react to prisoner fate.</p><div class="partyGrid">${choices}</div>${S.party.length==3?btn('Begin at Gallowsford Gate','go("map")','pri'):''}</div>`};
function companionCard(id){let c=comp(id),st=S.companionState[id]||{loyalty:0,stress:0,wound:0};let loyalty=st.loyalty>0?tag('loyal '+st.loyalty,'green'):st.loyalty<0?tag('disloyal '+(-st.loyalty),'red'):'';let stress=st.stress>0?tag('stress '+st.stress,'purple'):'';return `<div class="card companionCard">${portraitImg(id)}<div><div class="ct">${c.name} - ${c.role}</div><div class="cx">${c.text}<br><b>${c.ability}:</b> ${c.effect}<br>${(c.tags||[]).map(x=>tag(x)).join('')}${loyalty}${stress}</div></div></div>`}
function characterSheet(){let o=origin(S.origin),nextXp=P?.xpThresholds?.[S.level]||0;let xpPct=nextXp>0?Math.min(100,Math.floor((S.xp||0)/nextXp*100)):0;let xpBar=`<span class="xpBar"><span>XP ${S.xp||0}/${nextXp}</span><span class="xpFill" style="width:${xpPct}%"></span></span>`;return card('Character',`<b>${S.name||'Nameless'}</b> - ${S.backgroundTitle||''}<br>Origin: ${S.origin||'none'}<br>Level ${S.level} ${xpBar}<br>${Object.entries(S.stats).map(([k,v])=>tag(k+' '+v)).join('')}<br>Wounds: ${S.wounds||0}  Fatigue: ${S.fatigue||0}/6`)+perkList()}
company=function(){app.innerHTML=header()+`<div class="panel">${guidePanel()}${characterSheet()}<h2>Companions</h2>${S.party.map(companionCard).join('')||'<p>No companions selected.</p>'}<h3>Morale</h3>${tag(S.morale||0,S.morale<0?'red':'green')}<h3>Companion Reactions</h3>${reactionCards()||'<p>No major reaction yet.</p>'}<h3>Crimes</h3>${S.crimes.map(c=>tag(c,'red')).join('')||'<p>No recorded crimes.</p>'}</div>`};
function itemCard(id){let i=item(id);return `<div class="card itemCard">${itemIconHtml(i)}<div><div class="ct">${i.name} - ${i.type}</div><div class="cx">${i.text}<br>${(i.tags||[]).map(x=>tag(x)).join('')}</div></div></div>`}
pack=function(){app.innerHTML=header()+`<div class="panel">${guidePanel()}<h2>Pack & Papers</h2>${S.items.map(itemCard).join('')||'<p>No special items yet.</p>'}</div>`};
consequenceCards=function(){let f=Object.entries(S.fac).filter(([,v])=>v).map(([k,v])=>`<div class="factionRow">${factionMarkHtml(k)}<span>${D.factions[k].name}</span><b>${v>0?'+':''}${v}</b></div>`).join('')||'No faction shifts yet.';let c=S.crimes.length?S.crimes.map(x=>tag(x,'red')).join(''):'No recorded crimes.';let extra=S.consequenceLog.map(x=>card('Consequence',x)).join('');return card('Faction Changes',f)+card('Legal / Crime Record',c)+card('Party Morale',String(S.morale||0))+extra};
routeCards=function(chapter){return Object.entries(D.leads).filter(([,l])=>l.chapter==chapter).map(([k,l])=>{let state=S.leads[k]||'unknown',reward=l.item?`<span class="rewardLine">${itemIconHtml(l.item,'miniIcon')}${item(l.item).name}</span>`:'none',body=`${l.text}<br><b>Where:</b> ${n(l.node).name} - <b>Check:</b> ${l.stat.toUpperCase()} ${l.dc}<br>${leadCheckLine(l)}<br><b>Reward:</b> ${reward}<br><b>State:</b> ${tag(state,state=='viable'?'green':state=='failed_forward'?'red':state=='rumored'?'gold':'')}${l.transformsTo?'<br><b>Failed-forward:</b> '+l.transformsTo.map(x=>D.leads[x]?.name||x).join(', '):''}`;return card(l.name,body,routeCardAction(k,l,state))}).join('')};
nextStep=function(){let a=guideAction();return card('Next',recommendedNext(),btn(a.label,a.action,a.cls||''))};
title=function(){app.innerHTML=header()+`<div class="panel titlePanel">${scenePanel('gate')}<h2>v0.8.2-dev1 — RPG Foundation</h2><p>Character origins, XP/perks, road travel pressure, settlement hubs, companion depth.</p>${btn('New Game','reset()','pri')}${btn(hasStoredSave()?'Continue':'Start from saved draft','continueGame()','good')}${btn('Jump to Greyhook test state','devGreyhook()')}</div>`};

const navLabels={map:'Map',board:'Board',company:'Company',pack:'Pack',camp:'Camp'};
render=function(){save();nav.hidden=['title','origin','party'].includes(S.screen);if(!nav.hidden)nav.innerHTML=`<div class="navInner">${Object.keys(navLabels).map(x=>`<button class="${S.screen==x?'active':''}" onclick="go('${x}')">${navIcon(x)}<span>${navLabels[x]}</span></button>`).join('')}</div>`;try{({title,map,board,company,pack,camp,party,node:nodeScreen,settlement:settlementScreen,origin:originScreen}[S.screen]||map)()}catch(e){showRuntimeError(e,'render')}}; window.render=render;

try { render(); } catch(e) { showRuntimeError(e,'render'); }
